import{_ as a,a as t,b as o,c as r}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as i,o as l,c as n,a2 as d}from"./chunks/framework.DnrXFDHb.js";const C=JSON.parse('{"title":"Añadir un canal Google Drive","description":"","frontmatter":{},"headers":[],"relativePath":"es/upload/google-drive.md","filePath":"es/upload/google-drive.md","lastUpdated":1781962217000}'),c={name:"es/upload/google-drive.md"};function s(u,e,h,p,g,m){return l(),n("div",null,[...e[0]||(e[0]=[d('<h1 id="anadir-un-canal-google-drive" tabindex="-1">Añadir un canal Google Drive <a class="header-anchor" href="#anadir-un-canal-google-drive" aria-label="Permalink to &quot;Añadir un canal Google Drive&quot;">​</a></h1><p>El canal Google Drive usa una cuenta de Google Drive como destino de almacenamiento.</p><h2 id="que-preparar" tabindex="-1">Qué preparar <a class="header-anchor" href="#que-preparar" aria-label="Permalink to &quot;Qué preparar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>Uso</th></tr></thead><tbody><tr><td>Cuenta de Google</td><td>Gestionar Drive y OAuth</td></tr><tr><td>Proyecto de Google Cloud</td><td>Crear OAuth Client</td></tr><tr><td>Client ID / Client Secret</td><td>Autorizar a ImgBed</td></tr><tr><td>Refresh Token</td><td>Mantener acceso a largo plazo</td></tr><tr><td>Dominio ImgBed</td><td>Configurar callback OAuth</td></tr></tbody></table><h2 id="crear-oauth-client" tabindex="-1">Crear OAuth Client <a class="header-anchor" href="#crear-oauth-client" aria-label="Permalink to &quot;Crear OAuth Client&quot;">​</a></h2><p>En Google Cloud Console, crea un OAuth Client de tipo Web application.</p><p><img src="'+a+'" alt="Crear OAuth Client" loading="lazy"></p><p>Añade esta URI como redirección autorizada:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://tu-dominio/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+t+'" alt="Configurar URL OAuth" loading="lazy"></p><h2 id="rellenar-en-imgbed" tabindex="-1">Rellenar en ImgBed <a class="header-anchor" href="#rellenar-en-imgbed" aria-label="Permalink to &quot;Rellenar en ImgBed&quot;">​</a></h2><p>En Configuración de subida, elige <code>Google Drive</code> e introduce Client ID y Client Secret.</p><p><img src="'+o+'" alt="Configuración Google Drive" loading="lazy"></p><table tabindex="0"><thead><tr><th>Campo</th><th>Valor</th></tr></thead><tbody><tr><td>Nombre del canal</td><td>Por ejemplo <code>Google Drive Main</code></td></tr><tr><td>Client ID</td><td>OAuth Client ID</td></tr><tr><td>Client Secret</td><td>OAuth Client Secret</td></tr><tr><td>Refresh Token</td><td>Se obtiene después</td></tr><tr><td>Directorio raíz</td><td>Opcional, normalmente <code>imgbed</code></td></tr></tbody></table><h2 id="obtener-refresh-token" tabindex="-1">Obtener Refresh Token <a class="header-anchor" href="#obtener-refresh-token" aria-label="Permalink to &quot;Obtener Refresh Token&quot;">​</a></h2><ol><li>En ImgBed, haz clic en <code>Obtener Token</code>.</li><li>Inicia sesión con la cuenta de Google que será el destino.</li><li>Acepta los permisos.</li><li>Copia el Refresh Token mostrado en la página de callback.</li><li>Pégalo en el campo <code>Refresh Token</code>.</li></ol><p><img src="'+r+'" alt="Copiar Refresh Token" loading="lazy"></p><h2 id="verificacion" tabindex="-1">Verificación <a class="header-anchor" href="#verificacion" aria-label="Permalink to &quot;Verificación&quot;">​</a></h2><ol><li>Guarda el canal.</li><li>Sube una imagen de prueba.</li><li>Comprueba que aparece en Google Drive.</li><li>Abre el enlace devuelto por ImgBed.</li></ol><h2 id="notas" tabindex="-1">Notas <a class="header-anchor" href="#notas" aria-label="Permalink to &quot;Notas&quot;">​</a></h2><ul><li>Si la pantalla de consentimiento OAuth no está lista, la autorización puede fallar.</li><li>La cuenta que genera el Refresh Token será la cuenta de almacenamiento.</li><li>Si Drive no tiene espacio, la subida fallará.</li><li>No publiques el Client Secret.</li></ul>',21)])])}const _=i(c,[["render",s]]);export{C as __pageData,_ as default};
